const resp = $.steps.scrapeUrl.response || {};
const data = resp.data || resp;
const md = data.markdown || data.content || JSON.stringify(data).slice(0, 5000);
const url = $.input.url;
const wordCount = md.split(/\s+/).length;
const preview = md.slice(0, 4000);
return { content: preview, wordCount, url };

const data = $.steps.extractContent.output;
const prompt = `You are a content analyst. Analyze and summarize the following web page content.

SOURCE URL: ${data.url}
WORD COUNT: ${data.wordCount}

CONTENT:
${data.content}

Provide a comprehensive analysis. Return ONLY valid JSON with these keys:
{
  "title": "<page title or topic>",
  "summary": "<3-5 sentence summary of the main content>",
  "keyPoints": ["<point1>", "<point2>", "<point3>"],
  "contentType": "<article|documentation|product|blog|api|other>",
  "sentiment": "<positive|neutral|negative|mixed>",
  "actionableInsights": ["<insight1>", "<insight2>"]
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Analysis', summary: raw.slice(0, 1000), keyPoints: [], contentType: 'unknown', sentiment: 'neutral', actionableInsights: [] }; }

const ai = $.steps.parseAI.output;
const url = $.input.url;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ai.title || 'URL Analysis Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Source:* <' + url + '|' + url + '>\n*Type:* ' + (ai.contentType || 'unknown') + ' | *Sentiment:* ' + (ai.sentiment || 'neutral') } });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary*\n' + (ai.summary || 'No summary available.') } });
blocks.push({ type: 'divider' });

if (ai.keyPoints && ai.keyPoints.length > 0) {
  let kp = '*Key Points*\n';
  ai.keyPoints.forEach((p, i) => { kp += (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kp } });
  blocks.push({ type: 'divider' });
}

if (ai.actionableInsights && ai.actionableInsights.length > 0) {
  let ins = '*Actionable Insights*\n';
  ai.actionableInsights.forEach((a, i) => { ins += ':point_right: ' + a + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ins } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Fetched and analyzed by One CLI + Claude AI' }] });

const fallback = 'URL Analysis: ' + (ai.title || url);
return { blocks, fallback };
